  ('cpa-moex-01501', 'cpa', 'cpa-moex-102-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '下列關於應收帳款函證之敘述，何者正確？①查核人員若認為可不必函證，即得不函證  ②若受查者的', '["採積極式函證時，若客戶回函指出與帳載相符，則 函證之查核作業即告完成", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "c224286615ae", "answer_pdf_sha1": "4277af429395", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "審計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 19, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01502', 'cpa', 'cpa-moex-102-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '查核人員查閱法律及其他專業服務費用之內容，其主要目的為何？', '["獲取對受查者事業之瞭解", "瞭解是否有涉及或有事項之未決法律案件", "瞭解受查者之控制環境", "考量是否必須徵詢法律專家意見"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "c224286615ae", "answer_pdf_sha1": "4277af429395", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "審計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01503', 'cpa', 'cpa-moex-102-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '會計師於受託查核財務報表時，前期財務報表如未經會計師查核，該會計師應如何處理？', '["於本期查核報告敘明前期財務報表未經查核之事實", "要求受查者不得將前期財務報表與本期併列", "對前期財務報表出具無法表示意見之查核報告", "對前期財務報表進行核閱"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "c224286615ae", "answer_pdf_sha1": "4277af429395", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "審計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01504', 'cpa', 'cpa-moex-102-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '查核人員盤點受查者之現金時，應與下列何者同時進行？', '["評估現金方面之內部控制", "盤點固定資產", "盤點存貨", "盤點有價證券"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "c224286615ae", "answer_pdf_sha1": "4277af429395", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "審計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01505', 'cpa', 'cpa-moex-102-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '關於審計抽樣之敘述，下列何者正確？', '["統計抽樣可以提供足夠與適切之查核證據，非統計抽樣則否", "採統計抽樣的好處之一，是查核人員在設計樣本及選取樣本時，只須依據統計原理執行即可，毋須運 用其專業判斷", "信賴不足風險及不當拒絕風險與查核之效率有關", "固有風險及控制風險之存在與審計抽樣程序有關"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "c224286615ae", "answer_pdf_sha1": "4277af429395", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "審計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01506', 'cpa', 'cpa-moex-102-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '有關統計抽樣、非統計抽樣與抽樣風險等的敘述，下列何者錯誤？', '["統計抽樣與非統計抽樣均存有抽樣風險", "非統計抽樣的抽樣風險無法作成統計檢定推論", "查核人員要求之信賴水準愈高，樣本量應愈大", "執行審計抽樣時，只要樣本量愈高，偵查風險即愈小"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "c224286615ae", "answer_pdf_sha1": "4277af429395", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "審計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01507', 'cpa', 'cpa-moex-102-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '有關會計師受託代編財務資訊之服務，下列敘述何者錯誤？', '["會計師得不具獨立性", "會計師應作適當規劃", "會計師應檢視所代編之財務資訊，並考量其格式是否適當", "對代編財務資訊是否允當表達，會計師應負消極確信之責"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "c224286615ae", "answer_pdf_sha1": "4277af429395", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "審計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01508', 'cpa', 'cpa-moex-102-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '年專門職業及技術人員高等考試律師、 代號：80360 會計師、不動產估價師、專利師考試試題 類    科：會計師 甲、申論題部分：（50分） 不必抄題，作答時請將試題題號及答案依照順序寫在申論試卷上，於本試題上作答者，不予計分。 請以藍、黑色鋼筆或原子筆在申論試卷上作答。', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "d0f8b7bc19be", "answer_pdf_sha1": "c2010f0175c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "成本會計與管理會計", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 102, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01509', 'cpa', 'cpa-moex-102-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '能月公司對甲產品採分步成本制度，某月份甲產品之實體數量與加工成本（平均投入）之相關資料 如下： 期初在製品存貨（36,000單位，完工比例30%）  $29,268 本期投入製造（60,000單位）    $319,788 期末在製品存貨（24,000單位，完工比例60%） 當月份並未出現任何損壞單位，請問在先進先出法下，加工成本之約當單位成本為多少元？', '["$3.701", "$4.617", "$4.040", "$4.230"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "d0f8b7bc19be", "answer_pdf_sha1": "c2010f0175c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "成本會計與管理會計", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01510', 'cpa', 'cpa-moex-102-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '假設文山公司按季計算實際間接成本分攤率，且第一季是淡季，則第一季：', '["實際變動間接成本分攤率會較低", "實際全部間接成本分攤率會較高", "實際固定間接成本分攤率會較低", "該月的產出會較高"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "d0f8b7bc19be", "answer_pdf_sha1": "c2010f0175c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "成本會計與管理會計", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01511', 'cpa', 'cpa-moex-102-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '明陽公司製造部門提出下年度預計生產量如下： 第一季  第二季  第三季  第四季 預計生產量  13,000  15,000  14,000  12,000 每單位需要0.8小時的直接人工，直接人工每小時工資率為$160。此外，變動製造費用率為每直接人 工小時$25，每季固定製造費用為$120,000，其中折舊費用為每季$8,000。 試問該公司下年度直接人工的支出預算是多少？', '["$6,570,000", "$6,815,000", "$6,912,000", "$7,120,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "d0f8b7bc19be", "answer_pdf_sha1": "c2010f0175c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "成本會計與管理會計", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01512', 'cpa', 'cpa-moex-102-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '永慶公司每月銷售90,000單位的飲料，單位售價與單位成本資料如下： 單位價格  $35 直接材料    $3 直接人工    $3 變動製造費用    $5 每單位平均固定製造費用  $6 變動行銷成本    $10 每單位平均固定行銷成本  $3 假設現有一批飲料即將過期，必須儘快賣出，否則超過飲用期限則需下架。試問這批貨的最低售價 為多少？', '["$10", "$11", "$17", "$21"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "d0f8b7bc19be", "answer_pdf_sha1": "c2010f0175c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "成本會計與管理會計", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01513', 'cpa', 'cpa-moex-102-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '全家公司生產單一產品，採標準分步成本制處理產品成本，材料A於製造開始時一次投入，加工到 50%時實施檢驗，並且剔除損壞單位，檢驗後再將材料 B 投入完好單位中，正常損壞為通過檢驗之 完好單位之5%，該公司某年度6月份相關資料如下： 標準單位成本（未含正常損壞）：材料A  $25 材料B  13 加工成本 30 試問調整損壞成本後之標準單位成本為多少元？', '["$68", "$69", "$70", "$71"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "d0f8b7bc19be", "answer_pdf_sha1": "c2010f0175c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "成本會計與管理會計", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01514', 'cpa', 'cpa-moex-102-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '承上題資料，若公司當月生產量資料為期初在製品 300 單位（完工程度 60%），本期投入數 1,500 單位，完工轉出數1,100單位，期末在製品500單位（完工程度40%），損壞品200單位，則期末在 製品成本為多少元？', '["$17,500", "$18,500", "$19,500", "$20,500"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "d0f8b7bc19be", "answer_pdf_sha1": "c2010f0175c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "成本會計與管理會計", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01515', 'cpa', 'cpa-moex-102-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '若原料標準單價低於實際單價，且原料實際用量低於標準用量，則下列對原料效率差異及彈性差異 之敘述何者最正確？ 原料效率差異    原料彈性差異 （甲）    有利    不利 （乙）    有利    不一定 （丙）    不利    不利 （丁）    不利    有利', '["甲", "乙", "丙", "丁"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "d0f8b7bc19be", "answer_pdf_sha1": "c2010f0175c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "成本會計與管理會計", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01516', 'cpa', 'cpa-moex-102-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '承德公司製造甲產品，標準固定製造費用分攤率為$40（每機器小時），下列為九月份固定製造費用 相關資訊： 實際結果    靜態預算 生產數量    10,000單位  12,000單位 機器小時    5,100小時  6,000小時 固定製造費用    $244,000  $240,000 試問該公司九月份固定製造費用生產數量差異（production-volume variance）為若干？', '["$4,000不利", "$36,000有利", "$40,000不利", "$44,000有利"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "d0f8b7bc19be", "answer_pdf_sha1": "c2010f0175c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "成本會計與管理會計", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01517', 'cpa', 'cpa-moex-102-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '臺中公司生產單一產品並使用實際成本法。本年度相關資訊如下：銷售量4,000單位，單位售價$45， 生產量6,000單位，變動製造成本$25,000，固定製造成本$72,000，變動銷售費用$45,000，固定銷售 費用$6,000。假設沒有期初存貨，試計算採用變動成本法（variable costing）及全部成本法（absorption costing）所產生的淨利差額為多少？', '["$36,000", "$34,000", "$26,000", "$24,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "d0f8b7bc19be", "answer_pdf_sha1": "c2010f0175c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "成本會計與管理會計", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01518', 'cpa', 'cpa-moex-102-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '崑山公司於97年成立，該年度生產200,000單位之產品，並出售170,000單位，生產成本包括直接 材料$650,000，直接人工$300,000，變動製造費用$150,000，固定製造費用$487,500，崑山公司在變 動成本法下之期末存貨成本為若干？', '["$360,125", "$238,125", "$202,500", "$165,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "d0f8b7bc19be", "answer_pdf_sha1": "c2010f0175c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "成本會計與管理會計", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01519', 'cpa', 'cpa-moex-102-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '達利公司計畫生產甲產品100,000單位，每單位售價為$8，以及乙產品200,000單位，每單位售價為 $6。甲及乙產品之變動成本分別為售價的 30%及 25%。若達利公司預定營業利潤為$270,000，則總 固定成本應為多少元？', '["$1,190,000", "$1,200,000", "$1,450,000", "$1,750,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "d0f8b7bc19be", "answer_pdf_sha1": "c2010f0175c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "成本會計與管理會計", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01520', 'cpa', 'cpa-moex-102-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '西子灣公司預測明年度營運績效如下： 銷貨收入  $400,000 安全邊際（收入）  $100,000 邊際貢獻率  72% 試問西子灣公司明年度的總固定成本預期是多少？', '["$75,000", "$100,000", "$200,000", "$216,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "d0f8b7bc19be", "answer_pdf_sha1": "c2010f0175c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "成本會計與管理會計", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01521', 'cpa', 'cpa-moex-102-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '新一公司將直接原料加工製造成機車使用的零組件。下列為該公司本年度7月及8月的營運相關資 料： 7月    8月 產出數量（個）    56,000 50,000 直接原料用量（磅數）    10,000 9,000 直接原料成本（每磅）    $10 $8 直接人工小時    3,000 2,800 直接人工工資（每小時）    $60 $75 新一公司7月份之全部要素生產力（total factor productivity）為何？', '["5.6", "0.56", "0.2", "0.18"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "d0f8b7bc19be", "answer_pdf_sha1": "c2010f0175c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "成本會計與管理會計", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01522', 'cpa', 'cpa-moex-102-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '台一公司生產餅乾和糖果，98年度營運資料如下： 產品  預計  實際 種類  單位售價 單位成本  銷售量  單位售價 單位成本 銷售量 餅乾  $30 $20  6,000 $32 $22 6,400 糖果  20 14  8,000 22 15 7,000', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "d0f8b7bc19be", "answer_pdf_sha1": "c2010f0175c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "成本會計與管理會計", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 14, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01523', 'cpa', 'cpa-moex-102-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '年度，餅乾與糖果預計分攤的固定成本分別為$30,000 與$32,000，實際分攤之固定成本則為 $38,400與$42,000。台一公司98年度之邊際貢獻價格差異為多少？', '["$4,000有利", "$7,000有利", "$23,400有利", "$27,400有利"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "d0f8b7bc19be", "answer_pdf_sha1": "c2010f0175c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "成本會計與管理會計", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 98, "answer_corrected": false, "flags": ["answer_missing"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01524', 'cpa', 'cpa-moex-102-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '龍山公司是一個跨國公司，其生產據點設在稅率較低的國家，銷售據點設在稅率較高的國家。從節 稅的目的而言，龍山公司應如何處理？', '["停止在低稅率國家生產工作", "停止在高稅率國家行銷工作", "當其生產據點銷售產品至其銷售據點時，採用低轉撥價格", "當其生產據點銷售產品至其銷售據點時，採用高轉撥價格"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "d0f8b7bc19be", "answer_pdf_sha1": "c2010f0175c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "成本會計與管理會計", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01525', 'cpa', 'cpa-moex-102-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '向興公司的A事業部生產B事業部所需的零件，製造成本如下：每單位之直接材料、直接人工、變 動製造費用、固定製造費用（以實際產能250,000單位計算）分別為$30、$8、$10與$12。固定銷售 與管理成本為$1,200,000，變動銷售費用每單位$4。A事業部每年可以生產250,000單位，該零件每 單位可以$90賣到外部市場，預計下年度可賣200,000單位。如果該零件賣給B事業部，可以省去變 動銷售費用。B事業部可以每單位$80從外部市場買到相同的零件，預計下年度需要40,000單位。 如果B事業部下年度需要的40,000單位，都以每單位$56向A事業部購買，則公司淨利影響為何？', '["增加$1,280,000", "減少$1,280,000", "增加$1,380,000", "減少$1,380,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "d0f8b7bc19be", "answer_pdf_sha1": "c2010f0175c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "成本會計與管理會計", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL)
